head.script:
scwin.hid_chkCvsslMgntNo = ""; // 본선관리번호
scwin.hid_chkLineCd = "";      // LINE
scwin.hid_chkBilgClntNo = "";  // 청구처
scwin.hid_chkRegId = "";       // 등록자 ID
scwin.hid_chkRegBranCd = "";   // 등록점소코드
scwin.hid_autoOrderYn = "";    // 자동오더조회 여부
scwin.hid_autoOdrYn = "";      // 자동오더여부
scwin.hid_checkOrder = "";     // 오더정보조회 확인
scwin.hid_pageClsCd = "D"      // 화면구분코드(D:DONGBU)

scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strPreDate = $c.date.addDate(scwin.strCurDate, -7);
scwin.strBulkOrderUrl = "ui/ds/sd/odrmgnt/odrreg/sd_402_01_02t.xml";
scwin.strContainerOrderUrl = "ui/ds/sd/odrmgnt/odrreg/sd_402_01_11t.xml";
scwin.strContainerOrderUrl2 = "ui/ds/sd/odrmgnt/odrreg/sd_402_01_61b.xml";
scwin.ntisUrl = "http://ntis.dongwon.com";
scwin.debisUrl = "http://debis.dongwon.com";
scwin.userId = $c.data.getMemInfo("userId");
scwin.userNm = $c.data.getMemInfo("userNm");
scwin.userEmail = $c.data.getMemInfo("email");
scwin.retrieveSuccess = false;
scwin.checkOrder = false;

scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "OP194", compID: "lc_impExpDomesticClsCd" },
        { grpCd: "OP190", compID: "lc_transCargoClsCd" },
        { grpCd: "SD113", compID: "lc_odrKndCd" },
        { grpCd: "SD114", compID: "lc_selfClsCd" },
        { grpCd: "SD164", compID: "lc_stvOdrClsCd" },
    ];

    $c.data.setCommonCode(codeOptions, scwin.callbackCombo);
};

scwin.callbackCombo = function () {
    scwin.insertDatalist(dlt_commonCodeOP194);
    scwin.insertDatalist(dlt_commonCodeOP190);
    scwin.insertDatalist(dlt_commonCodeSD113);
    scwin.insertDatalist(dlt_commonCodeSD114);
    scwin.insertDatalist(dlt_commonCodeSD164);

    // 초기값 이벤트발생안해서 호출
    scwin.f_checkAuctoOrder();
}

scwin.onUdcCompleted = function () {
    txt_cvsslMgntNm.hide();

    // 초기화
    scwin.f_defaultValue();

    if (scwin.userId == "281776") {
        btnAutoSel.hide();
    }

    // 초기값 이벤트발생안해서 호출
    scwin.lc_odrSearchDt_onchange();
    scwin.lc_bookingBl_onchange();
};

// 조회
scwin.f_Retrieve = async function (e) {
    if (lc_odrSearchDt.getSelectedIndex() == 0) {
        // 오더기간 From - To 입력 확인
        if (!await $c.gus.cfValidate([ed_odrDtFrom, ed_odrDtTo])) {
            return;
        }

        // 오더기간 범위 확인  
        if (!await $c.gus.cfIsAfterDate(ed_odrDtFrom.getValue(), ed_odrDtTo.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["오더기간 From", "오더기간 To"]);
            ed_odrDtFrom.focus();
            return false;
        }

        let diffObj = await $c.gus.cfDifferBetween(ed_odrDtFrom.getValue(), ed_odrDtTo.getValue());

        // 오더기간이 1달 이상인경우 확인
        if (diffObj.year > 0 || diffObj.month > 0 && !scwin.checkOrder) {
            let chk = await $c.win.confirm("오더기간 이 1개월이 넘습니다.조회하시겠습니까?");

            if (!chk) {
                ed_odrDtFrom.focus();
                return false;
            }
        }
    } else if (lc_odrSearchDt.getSelectedIndex() == 1) {
        // 출발일자 From - To 입력 확인
        if (!await $c.gus.cfValidate([ed_odrWrkDtFrom, ed_odrWrkDtTo])) {
            return;
        }

        // 오더기간 범위 확인
        if (!await $c.gus.cfIsAfterDate(ed_odrWrkDtFrom.getValue(), ed_odrWrkDtTo.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["출발일자 From", "출발일자 To"]);
            ed_odrWrkDtFrom.focus();
            return false;
        }

        let diffObj = await $c.gus.cfDifferBetween(ed_odrWrkDtFrom.getValue(), ed_odrWrkDtTo.getValue());

        // 출발일자기간이 1달 이상인경우 확인
        if (diffObj.year > 0 || diffObj.month > 0) {
            let chk = await $c.win.confirm("출발일자 기간이 1개월이 넘습니다.조회하시겠습니까?");

            if (!chk) {
                ed_odrWrkDtFrom.focus();
                return false;
            }
        }
    }

    // 오더번호가 입력된 경우 오더번호 형식 확인
    if (ed_odrNo.getValue().length > 0) {
        if (!await $c.gus.cfValidate([ed_odrNo])) {
            return false;
        }
    }

    scwin.checkOrder = false;
    dma_orderRetrieve.set("autoOrderYn", scwin.hid_autoOrderYn);
    dma_orderRetrieve.set("pageClsCd", scwin.hid_pageClsCd);

    $c.sbm.execute(sbm_Retrieve);
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_searchCondition);

    lc_odrSearchDt.setSelectedIndex(0, true);

    ed_odrDtFrom.setValue(scwin.strPreDate);
    ed_odrDtTo.setValue(scwin.strCurDate);

    lc_odrKndCd.focus();
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {
    dma_orderRetrieve.setEmptyValue();

    scwin.f_FieldClear();

    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();

    scwin.f_setGridColumn();
};

