//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    let pWhere = "";

    switch (disGubun) {
        case 1:
            // 본선관리번호	
            pWhere = dlt_commonCodeSD113.getCellData(lc_odrKndCd.getSelectedIndex(), "fltrCd2"); 	// 수출입구분코드 : SD060 - 수입(I), 수출(E)

            let data = new Array(2);
            data[0] = pCode;
            data[1] = pWhere;

            let opt = {
                id: "op_204_01_07p"
                , title: "본선관리번호검색팝업"
                , popupName: "본선관리번호검색팝업"
                , modal: true
                , center: "yes"
                , type: "browserPopup"
                , width: "1200px"
                , height: "620px"
                , scroll: "yes"
                , resizable: "yes"
                , status: "no"
            };

            let rtnList = await $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", opt, data);

            $c.gus.cfSetReturnValue(rtnList, ed_cvsslMgntNo, null);
            scwin.hid_chkCvsslMgntNo = rtnList[2];

            break;
        case 2:
            // LINE
            udc_line.cfCommonPopUp(function (rtnList) {
                $c.gus.cfSetReturnValue(rtnList, ed_lineCd, txt_lineNm);
            }	// XML상의 SELECT ID	
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "LINE,LINE코드,LINE명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
        case 3:
            // 청구처
