scwin.lc_impExpDomesticClsCd_onchange = function (info) {
    let v_impExpDomesticClsCd = lc_impExpDomesticClsCd.getValue();
    let v_transCargoClsCd = lc_transCargoClsCd.getValue();

    dlt_commonCodeSD113.removeColumnFilterAll();

    if (scwin.hid_autoOrderYn == "0") {
        if (!$c.gus.cfIsNull(v_impExpDomesticClsCd)) {
            if (v_impExpDomesticClsCd == DsConstants.IMP_CD) {
                if ($c.gus.cfIsNull(v_transCargoClsCd)) {
                    $c.data.dataListFilter(dlt_commonCodeSD113, "fltrCd2 == '" + DsConstants.IMP_CD + "' && fltrCd3 == '0'");
                } else if (v_transCargoClsCd == DsConstants.ODR_BULK) {
                    $c.data.dataListFilter(dlt_commonCodeSD113, "fltrCd1 == '" + DsConstants.ODR_BULK + "' && fltrCd2 == '" + DsConstants.IMP_CD + "' && fltrCd3 == '0'");
                } else if (v_transCargoClsCd == DsConstants.ODR_CNTR) {
                    $c.data.dataListFilter(dlt_commonCodeSD113, "fltrCd1 == '" + DsConstants.ODR_CNTR + "' && fltrCd2 == '" + DsConstants.IMP_CD + "' && fltrCd3 == '0'");
                }
            } else if (v_impExpDomesticClsCd == DsConstants.EXP_CD) {
                if ($c.gus.cfIsNull(v_transCargoClsCd)) {
                    $c.data.dataListFilter(dlt_commonCodeSD113, "fltrCd2 == '" + DsConstants.EXP_CD + "' && fltrCd3 == '0'");
                } else if (v_transCargoClsCd == DsConstants.ODR_BULK) {
                    $c.data.dataListFilter(dlt_commonCodeSD113, "fltrCd1 == '" + DsConstants.ODR_BULK + "' && fltrCd2 == '" + DsConstants.EXP_CD + "' && fltrCd3 == '0'");
                } else if (v_transCargoClsCd == DsConstants.ODR_CNTR) {
                    $c.data.dataListFilter(dlt_commonCodeSD113, "fltrCd1 == '" + DsConstants.ODR_CNTR + "' && fltrCd2 == '" + DsConstants.EXP_CD + "' && fltrCd3 == '0'");
                }
