};

scwin.customFormatter = function (data, formattedData, rowIndex, colIndex) {
    let colId = this.getColumnID(colIndex);

    if (colId == "odrDcsnYn") {
        let value = "미확정";

        if (data == "1") {
            value = "확정";
        }

        return value;
    } else if (colId == "odrCompleteYn") {
        let value = "";

        if (data == "0") {
            value = "미완료";
        } else if (data == "1") {
            value = "완료";
        } else if (data == "2") {
            value = "취소";
        }

        return value;
    } else if (colId == "selYn") {
        let value = "";

        if (data == "0") {
            value = "미완료";
        } else if (data == "1") {
            value = "완료";
        } else if (data == "") {
            value = "출항대상아님";
        }

        return value;
    } else if (colId == "hayukYn") {
        let value = "";

        if (data == "0") {
            value = "미완료";
        } else if (data == "1") {
            value = "완료";
        }

        return value;
    } else if (colId == "odrCnclYn") {
        let value = "";

        if (data == "1") {
            value = "취소";
        }

        return value;
    }
};
